import BcomComponent from "../common/component";
BcomComponent({
    props: {
        defaultData: {
            type: Object,
            observer(val) {
                this.set({
                    backgroundColor: val.backgroundColor,
                    boardColor: val.boardColor,
                    color: val.color,
                    size: val.size
                });
            }
        }
    },
    /**
     * 页面的初始数据
     */
    data: {
        backgroundColor: "",
        boardColor: "",
        color: "",
        size: 8,
        isShowColor: false,
        initColor: "",
        colorPickerTitle: "请选择"
    },

    methods: {
        lineSizeChange(e) {
            let val = e.detail.value;
            this.set({
                size: val
            });
        },
        cancelTap() {
            this.$emit("cancel");
        },
        confirmTap() {
            this.$emit("confirm", this.data);
        },
        colorConfirm(e) {
            const colorObj = e.detail;
            let obj = {
                isShowColor: false
            };
            obj[this.colorName] = colorObj.hex;
            this.set(obj);
            this.colorName = "";
        },
        colorCancel() {
            this.colorName = "";
            this.set({
                isShowColor: false
            });
        },
        showColorPicker(e) {
            this.colorName = e.currentTarget.dataset.name;
            const colorPickerTitle = e.currentTarget.dataset.title;
            const initColor = e.currentTarget.dataset.color;
            this.set({
                isShowColor: true,
                colorPickerTitle,
                initColor
            });
        }
    }

})